void MRFShrinkeageDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}

void MRFShrinkeageDlg::ClearAllSelections()
{
	if (!!_pRefSurfSelector)
		_pRefSurfSelector->ClearSelect();

	if (!!_pSegmentSelector)
		_pSegmentSelector->ClearSelect();

	if (!!_pVentGeomSetSelector)
		_pVentGeomSetSelector->ClearSelect();

	if (!!_pSipesGeomSetSelector)
		_pSipesGeomSetSelector->ClearSelect();
}